int getHighestInRow(int arr[][5], int rowNum) {
    int highest = arr[rowNum][0]; // assume first is highest for now
    for (int col = 1; col < 5; col++) { // iterate through the columns but start at the 2nd one because we set the 1st one as initial
        if (arr[rowNum][col] > highest) { // if it returns true
            highest = arr[rowNum][col]; // then update the highest var
        }
    }
    return highest;
}
